// ── สร้างข้อความสรุปออเดอร์ ──────────────────────────────────
const generateOrderSummary = (cart, tableType, tableNum, note) => {
  let header = "";
  if (tableType === "delivery") {
    header = `ประเภทออเดอร์: Delivery 🛵`;
  } else if (tableType === "takeaway") {
    header = `ประเภทออเดอร์: Take Away 🥡`;
  } else {
    header = `ประเภทออเดอร์: โต๊ะ 🪑\nโต๊ะ: ${tableNum}`;
  }
  const items = cart.map(e => {
    const optsText = e.opts.length > 0 ? "\n" + e.opts.map(o => `    · ${o.label}`).join("\n") : "";
    return `• ${e.item.name} ${e.unitPrice}฿${optsText}\n    จำนวน ${e.qty}`;
  }).join("\n");
  const total = cart.reduce((s,e) => s + e.unitPrice * e.qty, 0);
  let footer = `ราคารวม: ${total}฿`;
  if (note) footer += `\nหมายเหตุ: ${note}`;
  if (tableType === "takeaway") footer += "\n\nกรุณาแนบสลิปในแชท LINE OA หลังส่งออเดอร์";
  if (tableType === "delivery") footer += "\n\nกรุณาแนบสลิปและส่งโลเคชั่นในแชท LINE OA หลังส่งออเดอร์";
  return `🍖 ขาหมูนาย ต.\n${header}\n\nรายการอาหาร:\n${items}\n\n${footer}`;
};

const sendOrderToLine = (text) => {
  window.open(`https://line.me/R/oaMessage/${LINE_OA_ID}/?text=${encodeURIComponent(text)}`, "_blank");
};

